const roles = [
  "Software Engineer",
  "Product Manager",
  "Data Scientist",
  "UX Designer",
  "DevOps Engineer",
  "Marketing Manager",
  "Sales Representative",
  "Business Analyst",
];

const difficulties = ["Easy", "Medium", "Hard"];

export function NewSessionDialog({
  open,
  onOpenChange,
  onSessionCreated,
