                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label htmlFor="company">Company</Label>
            <Input
              id="company"
              placeholder="e.g. Google, Amazon, Meta..."
              value={company}
              onChange={(e) => setCompany(e.target.value)}
