import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Mic, Square, Play, Pause, Trash2, Check } from "lucide-react";
import { WaveformVisualizer } from "./waveform-visualizer";
import { submitAnswer } from "@/lib/api";
import { useSpeech } from "@/contexts/SpeechContext";

interface AudioRecorderProps {
  questionId: string;
  sessionId: string;
  onRecordingComplete: (questionId: string, audioBlob: Blob) => void;
  hasRecording: boolean;
}

export function AudioRecorder({
  questionId,
  sessionId,
  onRecordingComplete,
  hasRecording,
}: AudioRecorderProps) {
  const [isRecording, setIsRecording] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
      if (streamRef.current) {
        streamRef.current.getTracks().forEach((track) => track.stop());
      }
      if (audioUrl) {
        URL.revokeObjectURL(audioUrl);
      }
    };
  }, [audioUrl]);

  const {
    startListening,
    stopListening,
    resetTranscript,
    transcript,
    isListening: isListeningSpeech,
  } = useSpeech();

  async function startRecording() {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = () => {
        const blob = new Blob(audioChunksRef.current, { type: "audio/webm" });
        setAudioBlob(blob);
        const url = URL.createObjectURL(blob);
        setAudioUrl(url);
        stream.getTracks().forEach((track) => track.stop());
        stopListening(); // Stop STT
      };

      mediaRecorder.start();
      setIsRecording(true);
      setIsPaused(false);
      setRecordingTime(0);
      resetTranscript(); // Clear previous transcript
      startListening(); // Start STT

      timerRef.current = setInterval(() => {
        setRecordingTime((prev) => prev + 1);
      }, 1000);
    } catch (error) {
      console.error("Failed to start recording:", error);
      alert("Failed to access microphone. Please check your permissions.");
    }
  }

  function stopRecording() {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsPaused(false);
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    }
  }

  function pauseRecording() {
    if (mediaRecorderRef.current && isRecording) {
      if (isPaused) {
        mediaRecorderRef.current.resume();
        startListening(); // Resume STT
        timerRef.current = setInterval(() => {
          setRecordingTime((prev) => prev + 1);
        }, 1000);
      } else {
        mediaRecorderRef.current.pause();
        stopListening(); // Pause STT
        if (timerRef.current) {
          clearInterval(timerRef.current);
        }
      }
      setIsPaused(!isPaused);
    }
  }

  function playRecording() {
    if (audioUrl && audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
      } else {
        audioRef.current.play();
        setIsPlaying(true);
      }
    }
  }

  function deleteRecording() {
    if (audioUrl) {
      URL.revokeObjectURL(audioUrl);
    }
    setAudioBlob(null);
    setAudioUrl(null);
    setRecordingTime(0);
    setIsPlaying(false);
    resetTranscript();
  }

  async function handleSubmit() {
    if (!audioBlob) return;

    try {
      setIsSubmitting(true);
      await submitAnswer({
        sessionId,
        questionId,
        questionIndex: 0,
        text: transcript || '',
        audioBlob,
      });
      onRecordingComplete(questionId, audioBlob);
      resetTranscript();
    } catch (error) {
      console.error("Failed to submit answer:", error);
      // For demo, just mark as complete
      onRecordingComplete(questionId, audioBlob);
    } finally {
      setIsSubmitting(false);
    }
  }

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, "0")}`;
  };

  return (
    <Card>
      <CardContent className="p-8">
        <div className="space-y-6">
          {/* Status Badge */}
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-2">
              {isRecording && (
                <Badge variant="destructive" className="animate-pulse">
                  <div className="w-2 h-2 bg-white rounded-full mr-2" />
                  Recording
                </Badge>
              )}
              {audioBlob && !isRecording && (
                <Badge variant="secondary">
                  <Check className="w-3 h-3 mr-1" />
                  Recorded
                </Badge>
              )}
            </div>
            {(isRecording || audioBlob) && (
              <div className="text-2xl font-mono font-bold">
                {formatTime(recordingTime)}
              </div>
            )}
          </div>

          {/* Waveform Visualizer */}
          <div className="relative h-32 bg-muted/30 rounded-lg overflow-hidden">
            {isRecording && streamRef.current && (
              <WaveformVisualizer stream={streamRef.current} isActive={!isPaused} />
            )}
            {!isRecording && !audioBlob && (
              <div className="absolute inset-0 flex items-center justify-center text-muted-foreground">
                <Mic className="w-12 h-12 opacity-20" />
              </div>
            )}
            {audioBlob && !isRecording && (
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="text-center">
                  <Play className="w-12 h-12 mx-auto mb-2 text-primary" />
                  <p className="text-sm text-muted-foreground">
                    Click play to review your answer
                  </p>
                </div>
              </div>
            )}
          </div>

          {/* Controls */}
          <div className="flex items-center justify-center space-x-4">
            <AnimatePresence mode="wait">
              {!isRecording && !audioBlob && (
                <motion.div
                  key="start"
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  exit={{ scale: 0 }}
                >
                  <Button
                    size="lg"
                    className="rounded-full w-16 h-16"
                    onClick={startRecording}
                  >
                    <Mic className="w-6 h-6" />
                  </Button>
                </motion.div>
              )}

              {isRecording && (
                <motion.div
                  key="recording"
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  exit={{ scale: 0 }}
                  className="flex items-center space-x-4"
                >
                  <Button
                    size="lg"
                    variant="outline"
                    className="rounded-full w-12 h-12"
                    onClick={pauseRecording}
                  >
                    {isPaused ? (
                      <Play className="w-5 h-5" />
                    ) : (
                      <Pause className="w-5 h-5" />
                    )}
                  </Button>
                  <Button
                    size="lg"
                    variant="destructive"
                    className="rounded-full w-16 h-16"
                    onClick={stopRecording}
                  >
                    <Square className="w-6 h-6" />
                  </Button>
                </motion.div>
              )}

              {audioBlob && !isRecording && (
                <motion.div
                  key="playback"
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  exit={{ scale: 0 }}
                  className="flex items-center space-x-4"
                >
                  <Button
                    size="lg"
                    variant="outline"
                    className="rounded-full w-12 h-12"
                    onClick={deleteRecording}
                  >
                    <Trash2 className="w-5 h-5" />
                  </Button>
                  <Button
                    size="lg"
                    variant="outline"
                    className="rounded-full w-16 h-16"
                    onClick={playRecording}
                  >
                    {isPlaying ? (
                      <Pause className="w-6 h-6" />
                    ) : (
                      <Play className="w-6 h-6" />
                    )}
                  </Button>
                  <Button
                    size="lg"
                    className="rounded-full px-8"
                    onClick={handleSubmit}
                    disabled={isSubmitting || hasRecording}
                  >
                    {hasRecording ? (
                      <>
                        <Check className="w-5 h-5 mr-2" />
                        Submitted
                      </>
                    ) : (
                      "Submit Answer"
                    )}
                  </Button>
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          {/* Hidden audio element for playback */}
          {audioUrl && (
            <audio
              ref={audioRef}
              src={audioUrl}
              onEnded={() => setIsPlaying(false)}
              className="hidden"
            />
          )}
        </div>
      </CardContent>
    </Card>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import {
  Mic,
  MicOff,
  Video,
  VideoOff,
  PhoneOff,
  Volume2,
  VolumeX,
  User,
} from "lucide-react";
import { submitAnswer } from "@/lib/api";

interface VideoCallInterfaceProps {
  sessionId: string;
  question: string;
  questionNumber: number;
  totalQuestions: number;
  onNextQuestion: () => void;
  onEndInterview: () => void;
}

export function VideoCallInterface({
  sessionId,
  question,
  questionNumber,
  totalQuestions,
  onNextQuestion,
  onEndInterview,
}: VideoCallInterfaceProps) {
  const [isMicOn, setIsMicOn] = useState(false);
  const [isVideoOn, setIsVideoOn] = useState(true);
  const [isSpeakerOn, setIsSpeakerOn] = useState(true);
  const [isRecording, setIsRecording] = useState(false);
  const [silenceTimer, setSilenceTimer] = useState(0);
  const [audioLevel, setAudioLevel] = useState(0);
  const [recordingTime, setRecordingTime] = useState(0);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const streamRef = useRef<MediaStream | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const silenceTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const recordingIntervalRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach((track) => track.stop());
      }
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
      if (silenceTimeoutRef.current) {
        clearTimeout(silenceTimeoutRef.current);
      }
      if (recordingIntervalRef.current) {
        clearInterval(recordingIntervalRef.current);
      }
    };
  }, []);

  async function startRecording() {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      // Setup audio analysis
      const audioContext = new AudioContext();
      audioContextRef.current = audioContext;
      const source = audioContext.createMediaStreamSource(stream);
      const analyser = audioContext.createAnalyser();
      analyser.fftSize = 256;
      source.connect(analyser);
      analyserRef.current = analyser;

      // Start recording
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const blob = new Blob(audioChunksRef.current, { type: "audio/webm" });
        await handleSubmitAnswer(blob);
        stream.getTracks().forEach((track) => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setIsMicOn(true);
      setRecordingTime(0);

      // Start recording timer
      recordingIntervalRef.current = setInterval(() => {
        setRecordingTime((prev) => prev + 1);
      }, 1000);

      // Start monitoring audio levels and silence
      monitorAudioLevels();
    } catch (error) {
      console.error("Failed to start recording:", error);
      alert("Failed to access microphone. Please check your permissions.");
    }
  }

  function monitorAudioLevels() {
    if (!analyserRef.current) return;

    const analyser = analyserRef.current;
    const dataArray = new Uint8Array(analyser.frequencyBinCount);

    const checkAudio = () => {
      if (!isRecording) return;

      analyser.getByteFrequencyData(dataArray);
      const average = dataArray.reduce((a, b) => a + b) / dataArray.length;
      setAudioLevel(average);

      // Silence detection (threshold: 5)
      if (average < 5) {
        setSilenceTimer((prev) => {
          const newValue = prev + 0.1;

          // Auto-advance after 6 seconds of silence
          if (newValue >= 6) {
            stopRecording();
            return 0;
          }
          return newValue;
        });
      } else {
        setSilenceTimer(0);
      }

      requestAnimationFrame(checkAudio);
    };

    checkAudio();
  }

  function stopRecording() {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsMicOn(false);
      setSilenceTimer(0);

      if (recordingIntervalRef.current) {
        clearInterval(recordingIntervalRef.current);
      }
    }
  }

  async function handleSubmitAnswer(audioBlob: Blob) {
    try {
      await submitAnswer({
        sessionId,
        questionId: `q${questionNumber}`,
        questionIndex: questionNumber - 1,
        text: '',
        audioBlob,
      });

      // Wait a moment then move to next question
      setTimeout(() => {
        if (questionNumber < totalQuestions) {
          onNextQuestion();
        } else {
          onEndInterview();
        }
      }, 1000);
    } catch (error) {
      console.error("Failed to submit answer:", error);
      // Still advance even if submission fails
      setTimeout(() => {
        if (questionNumber < totalQuestions) {
          onNextQuestion();
        } else {
          onEndInterview();
        }
      }, 1000);
    }
  }

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, "0")}`;
  };

  return (
    <div className="min-h-screen bg-background flex flex-col">
      {/* Top Bar */}
      <div className="bg-card border-b border-border p-4">
        <div className="container mx-auto flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <Badge variant={isRecording ? "destructive" : "secondary"} className={isRecording ? "animate-pulse" : ""}>
              {isRecording ? (
                <>
                  <div className="w-2 h-2 bg-white rounded-full mr-2" />
                  Recording
                </>
              ) : (
                "Ready"
              )}
            </Badge>
            <div className="text-sm text-muted-foreground">
              Question {questionNumber} of {totalQuestions}
            </div>
            {isRecording && (
              <div className="text-sm font-mono">{formatTime(recordingTime)}</div>
            )}
          </div>
          <Progress value={(questionNumber / totalQuestions) * 100} className="w-48" />
        </div>
      </div>

      {/* Main Video Area */}
      <div className="flex-1 p-6 grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* AI Interviewer - Large */}
        <div className="lg:col-span-2">
          <Card className="h-full bg-black overflow-hidden relative">
            <div className="absolute inset-0 flex items-center justify-center">
              <motion.div
                animate={{
                  scale: isSpeakerOn ? [1, 1.05, 1] : 1,
                }}
                transition={{
                  duration: 2,
                  repeat: Infinity,
                  ease: "easeInOut",
                }}
                className="w-48 h-48 rounded-full bg-gradient-to-br from-primary to-secondary flex items-center justify-center"
              >
                <User className="w-24 h-24 text-white" />
              </motion.div>
            </div>

            {/* AI Label */}
            <div className="absolute bottom-6 left-6 bg-black/80 backdrop-blur-sm px-4 py-2 rounded-full flex items-center space-x-2">
              <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
              <span className="text-white font-medium">AI Interviewer</span>
            </div>

            {/* Audio Indicator */}
            {isSpeakerOn && (
              <div className="absolute top-6 right-6">
                <motion.div
                  animate={{ scale: [1, 1.2, 1] }}
                  transition={{ duration: 1, repeat: Infinity }}
                >
                  <Volume2 className="w-6 h-6 text-white" />
                </motion.div>
              </div>
            )}
          </Card>
        </div>

        {/* User Video - Small */}
        <div className="lg:col-span-1">
          <Card className="h-full bg-muted overflow-hidden relative">
            <div className="absolute inset-0 flex items-center justify-center">
              {isVideoOn ? (
                <div className="text-center">
                  <div className="w-32 h-32 rounded-full bg-gradient-to-br from-muted-foreground/20 to-muted-foreground/10 flex items-center justify-center mb-4 mx-auto">
                    <User className="w-16 h-16 text-muted-foreground" />
                  </div>
                  <p className="text-sm text-muted-foreground">Camera Preview</p>
                </div>
              ) : (
                <div className="text-center">
                  <VideoOff className="w-16 h-16 text-muted-foreground mb-4 mx-auto" />
                  <p className="text-sm text-muted-foreground">Camera Off</p>
                </div>
              )}
            </div>

            {/* User Label */}
            <div className="absolute bottom-4 left-4 bg-black/80 backdrop-blur-sm px-3 py-1 rounded-full flex items-center space-x-2">
              <span className="text-white text-sm">You</span>
              {isMicOn ? (
                <Mic className="w-3 h-3 text-green-500" />
              ) : (
                <MicOff className="w-3 h-3 text-red-500" />
              )}
            </div>

            {/* Audio Level Indicator */}
            {isRecording && audioLevel > 0 && (
              <div className="absolute top-4 left-4 right-4">
                <div className="h-1 bg-muted-foreground/20 rounded-full overflow-hidden">
                  <motion.div
                    className="h-full bg-primary"
                    style={{ width: `${Math.min(audioLevel, 100)}%` }}
                  />
                </div>
              </div>
            )}
          </Card>
        </div>
      </div>

      {/* Question Display */}
      <div className="bg-card border-t border-border p-6">
        <div className="container mx-auto">
          <div className="max-w-4xl mx-auto">
            <h3 className="text-2xl font-bold mb-4 text-center">{question}</h3>

            {isRecording && silenceTimer > 0 && (
              <div className="text-center">
                <p className="text-sm text-muted-foreground mb-2">
                  Silence detected: {Math.floor(silenceTimer)}s / 6s
                </p>
                <Progress value={(silenceTimer / 6) * 100} className="w-64 mx-auto" />
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Control Bar */}
      <div className="bg-card border-t border-border p-4">
        <div className="container mx-auto">
          <div className="flex items-center justify-center space-x-4">
            <Button
              size="lg"
              variant={isMicOn ? "secondary" : "destructive"}
              className="rounded-full w-14 h-14"
              onClick={() => {
                if (!isRecording) {
                  startRecording();
                } else {
                  stopRecording();
                }
              }}
            >
              {isMicOn ? <Mic className="w-6 h-6" /> : <MicOff className="w-6 h-6" />}
            </Button>

            <Button
              size="lg"
              variant={isVideoOn ? "secondary" : "outline"}
              className="rounded-full w-14 h-14"
              onClick={() => setIsVideoOn(!isVideoOn)}
            >
              {isVideoOn ? <Video className="w-6 h-6" /> : <VideoOff className="w-6 h-6" />}
            </Button>

            <Button
              size="lg"
              variant={isSpeakerOn ? "secondary" : "outline"}
              className="rounded-full w-14 h-14"
              onClick={() => setIsSpeakerOn(!isSpeakerOn)}
            >
              {isSpeakerOn ? <Volume2 className="w-6 h-6" /> : <VolumeX className="w-6 h-6" />}
            </Button>

            <Button
              size="lg"
              variant="destructive"
              className="rounded-full w-14 h-14"
              onClick={onEndInterview}
            >
              <PhoneOff className="w-6 h-6" />
            </Button>
          </div>

          <div className="text-center mt-4 text-sm text-muted-foreground">
            {!isRecording ? (
              <p>Click the microphone to start answering</p>
            ) : (
              <p>Speak your answer. Interview will auto-advance after 6 seconds of silence.</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';

interface SpeechContextType {
    isListening: boolean;
    transcript: string;
    interimTranscript: string;
    startListening: () => void;
    stopListening: () => void;
    resetTranscript: () => void;
    error: string | null;
}

const SpeechContext = createContext<SpeechContextType | undefined>(undefined);

export function SpeechProvider({ children }: { children: React.ReactNode }) {
    const [isListening, setIsListening] = useState(false);
    const [transcript, setTranscript] = useState('');
    const [interimTranscript, setInterimTranscript] = useState('');
    const [error, setError] = useState<string | null>(null);
    const [recognition, setRecognition] = useState<any>(null);

    useEffect(() => {
        if (typeof window !== 'undefined') {
            // @ts-expect-error - SpeechRecognition is not in all browser type definitions
            const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;

            if (SpeechRecognition) {
                const recognitionInstance = new SpeechRecognition();
                recognitionInstance.continuous = true;
                recognitionInstance.interimResults = true;
                recognitionInstance.lang = 'en-US'; // Default to English

                recognitionInstance.onstart = () => {
                    setIsListening(true);
                    setError(null);
                };

                recognitionInstance.onend = () => {
                    setIsListening(false);
                };

                recognitionInstance.onerror = (event: any) => {
                    console.error('Speech recognition error', event.error);
                    setError(event.error);
                    setIsListening(false);
                };

                recognitionInstance.onresult = (event: any) => {
                    let final = '';
                    let interim = '';

                    for (let i = event.resultIndex; i < event.results.length; ++i) {
                        if (event.results[i].isFinal) {
                            final += event.results[i][0].transcript;
                        } else {
                            interim += event.results[i][0].transcript;
                        }
                    }

                    if (final) {
                        setTranscript((prev) => prev + ' ' + final);
                    }
                    setInterimTranscript(interim);
                };

                setRecognition(recognitionInstance);
            } else {
                setError('Browser does not support speech recognition.');
            }
        }
    }, []);

    const startListening = useCallback(() => {
        if (recognition && !isListening) {
            try {
                recognition.start();
            } catch (e) {
                console.error("Failed to start recognition", e);
            }
        }
    }, [recognition, isListening]);

    const stopListening = useCallback(() => {
        if (recognition && isListening) {
            recognition.stop();
        }
    }, [recognition, isListening]);

    const resetTranscript = useCallback(() => {
        setTranscript('');
        setInterimTranscript('');
    }, []);

    return (
        <SpeechContext.Provider
            value={{
                isListening,
                transcript,
                interimTranscript,
                startListening,
                stopListening,
                resetTranscript,
                error,
            }}
        >
            {children}
        </SpeechContext.Provider>
    );
}

export function useSpeech() {
    const context = useContext(SpeechContext);
    if (context === undefined) {
        throw new Error('useSpeech must be used within a SpeechProvider');
    }
    return context;
}

"use client";

import { createContext, useContext, useState, useEffect, ReactNode, useCallback } from "react";
import { useRouter } from "next/navigation";
import * as api from "@/lib/api";

interface User {
  id: string;
  email: string;
  name: string;
}

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  signIn: (email: string, password: string) => Promise<void>;
  signUp: (name: string, email: string, password: string) => Promise<void>;
  signOut: () => Promise<void>;
  resetPassword: (email: string) => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const router = useRouter();

  // On mount, hydrate user from cookie-based session
  useEffect(() => {
    async function hydrate() {
      try {
        // Cookie sent automatically with credentials: 'include'
        const userData = await api.getMe();
        setUser(userData);
      } catch (error) {
        // No valid session — user needs to sign in
        setUser(null);
      } finally {
        setIsLoading(false);
      }
    }

    hydrate();
  }, []);

  const signIn = useCallback(async (email: string, password: string) => {
    const { user: userData } = await api.signIn(email, password);
    setUser(userData);
    router.push("/dashboard");
  }, [router]);

  const signUp = useCallback(async (name: string, email: string, password: string) => {
    const { user: userData } = await api.signUp(name, email, password);
    setUser(userData);
    router.push("/dashboard");
  }, [router]);

  const signOut = useCallback(async () => {
    try {
      await api.signOut();
    } catch {
      // Even if the API call fails, clear local state
    }
    setUser(null);
    router.push("/sign-in");
  }, [router]);

  const resetPassword = useCallback(async (email: string) => {
    await api.resetPassword(email);
  }, []);

  return (
    <AuthContext.Provider
      value={{
        user,
        isLoading,
        signIn,
        signUp,
        signOut,
        resetPassword,
        isAuthenticated: !!user,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}

import { useState, useRef, useEffect, useCallback } from 'react';

interface UseInterviewAudioProps {
  onSilenceDetected: (audioBlob: Blob) => void;
  silenceThreshold?: number; // -50dB default
  silenceDuration?: number; // 2000ms default
}

export function useInterviewAudio({
  onSilenceDetected,
  silenceThreshold = -50,
  silenceDuration = 2000,
}: UseInterviewAudioProps) {
  const [isRecording, setIsRecording] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false); // User is speaking?
  
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const silenceTimerRef = useRef<NodeJS.Timeout | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const startRecording = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      
      // Setup Audio Setup for Silence Detection
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
      const analyser = audioContext.createAnalyser();
      const source = audioContext.createMediaStreamSource(stream);
      source.connect(analyser);
      
      analyser.fftSize = 256;
      analyser.minDecibels = -90;
      analyser.maxDecibels = -10;
      
      audioContextRef.current = audioContext;
      analyserRef.current = analyser;

      // Setup Recorder
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        onSilenceDetected(audioBlob);
        audioChunksRef.current = [];
        // Stop all tracks
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      detectSilence();

    } catch (err) {
      console.error("Error accessing microphone:", err);
    }
  }, [onSilenceDetected]);

  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsSpeaking(false);
      
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
      if (silenceTimerRef.current) {
        clearTimeout(silenceTimerRef.current);
      }
    }
  }, []);

  const detectSilence = () => {
    if (!analyserRef.current || !isRecording) return;

    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);
    analyserRef.current.getByteFrequencyData(dataArray);

    // Calculate average volume
    let sum = 0;
    for (let i = 0; i < bufferLength; i++) {
        sum += dataArray[i];
    }
    const average = sum / bufferLength;
    
    // Normalize roughly to dB (simplified)
    // 0 = silence, 128 = loud (approx range in Uint8)
    // Threshold ~20 is roughly silence
    
    if (average > 10) { // Speaking
        setIsSpeaking(true);
        if (silenceTimerRef.current) {
            clearTimeout(silenceTimerRef.current);
            silenceTimerRef.current = null;
        }
    } else { // Silent
        setIsSpeaking(false);
        if (!silenceTimerRef.current) {
            silenceTimerRef.current = setTimeout(() => {
                // Trigger auto-send
                stopRecording(); 
            }, silenceDuration);
        }
    }

    requestAnimationFrame(detectSilence);
  };
  
  // Clean up
  useEffect(() => {
      return () => {
          stopRecording();
      }
  }, []);

  return { isRecording, isSpeaking, startRecording, stopRecording };
}
